import { useEffect, useState } from "react";
import { useLocation } from "wouter";
import { calculatorRoutes } from "@/data/siteRoutes";
import ShareButton from "@/components/ShareButton";

const calculatorPaths = new Set(calculatorRoutes.map((route) => route.path));

function hasPageShareControls() {
  return Array.from(document.querySelectorAll("[data-calculation-history-root]")).some(
    (element) => !element.closest("[data-global-share-fallback]"),
  );
}

export default function ShareResultFallback() {
  const [location] = useLocation();
  const [shouldRender, setShouldRender] = useState(false);

  useEffect(() => {
    if (typeof document === "undefined" || !calculatorPaths.has(location)) {
      setShouldRender(false);
      return;
    }

    const update = () => setShouldRender(!hasPageShareControls());
    const timers = [100, 500, 1000].map((delay) => window.setTimeout(update, delay));
    const observer = new MutationObserver(update);
    observer.observe(document.body, { childList: true, subtree: true });
    update();

    return () => {
      timers.forEach((timer) => window.clearTimeout(timer));
      observer.disconnect();
    };
  }, [location]);

  if (!shouldRender) return null;

  return (
    <div data-global-share-fallback className="mx-auto max-w-3xl px-4 sm:px-6">
      <ShareButton />
    </div>
  );
}
